html:
{% set currency_symbol = frappe.db.get_value('Currency', doc.currency, 'symbol') or doc.currency or '' %}
{% set organization = doc.organization %}
{% set organization_doc = frappe.get_doc('CRM Organization', organization) if organization else None %}
{% set org_address = frappe.get_doc('Address', organization_doc.address) if organization_doc and organization_doc.address else None %}
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; color: #1a1a1a; }

  .pf { max-width: 780px; margin: 0 auto; padding: 48px 48px 40px; }

  /* ── Letterhead ── */
  .lh { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 28px; border-bottom: 3px solid #1a1a1a; margin-bottom: 32px; }
  .lh-logo { font-size: 22px; font-weight: 800; letter-spacing: -0.5px; color: #1a1a1a; }
  .lh-address { text-align: right; font-size: 11px; color: #666; line-height: 1.7; }

  /* ── Document Title ── */
  .doc-title { margin-bottom: 28px; }
  .doc-title h1 { font-size: 26px; font-weight: 700; letter-spacing: -0.3px; margin-bottom: 4px; }
  .doc-title .doc-meta { font-size: 11px; color: #888; display: flex; gap: 24px; }
  .doc-title .doc-meta span strong { color: #444; }

  /* ── To Block ── */
  .to-block { background: #f9f9f9; border-left: 3px solid #1a1a1a; padding: 14px 18px; margin-bottom: 28px; }
  .to-block .to-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.8px; color: #888; margin-bottom: 6px; }
  .to-block .to-name { font-size: 16px; font-weight: 600; margin-bottom: 2px; }
  .to-block .to-meta { font-size: 12px; color: #555; line-height: 1.8; }

  /* ── Section ── */
  .section { margin-bottom: 28px; }
  .section-title { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.2px; color: #888; border-bottom: 1px solid #e0e0e0; padding-bottom: 5px; margin-bottom: 14px; }
  .fields-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 14px 40px; }
  .field-row { }
  .field-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.5px; color: #999; margin-bottom: 2px; }
  .field-value { font-size: 13px; color: #1a1a1a; font-weight: 500; }
  .field-value.empty { color: #ccc; font-weight: 400; }

  /* ── Products Table ── */
  .products-table { width: 100%; border-collapse: collapse; font-size: 12px; margin-top: 4px; }
  .products-table thead tr { background: #1a1a1a; color: #fff; }
  .products-table th { padding: 9px 12px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.7px; font-weight: 600; text-align: left; }
  .products-table th.ar, .products-table td.ar { text-align: right; }
  .products-table tbody tr:nth-child(even) { background: #fafafa; }
  .products-table td { padding: 9px 12px; border-bottom: 1px solid #ececec; vertical-align: top; color: #333; }
  .totals-block { margin-top: 0; border-top: 2px solid #1a1a1a; }
  .totals-block .total-row { display: flex; justify-content: flex-end; padding: 8px 12px; border-bottom: 1px solid #ececec; gap: 40px; }
  .totals-block .total-row.grand { background: #1a1a1a; color: #fff; }
  .totals-block .tl { font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; min-width: 120px; text-align: right; }
  .totals-block .tv { font-size: 13px; font-weight: 700; min-width: 100px; text-align: right; }

  /* ── Footer ── */
  .pf-footer { margin-top: 40px; padding-top: 14px; border-top: 1px solid #e0e0e0; display: flex; justify-content: space-between; align-items: center; }
  .pf-footer .ref { font-size: 10px; color: #bbb; }
  .pf-footer .date { font-size: 10px; color: #bbb; }

  /* ── Divider ── */
  .divider { border: none; border-top: 1px solid #ececec; margin: 20px 0; }
</style>

<div class="pf">

  <!-- Letterhead -->
  <div class="lh">
    <div class="lh-logo">
      {% if organization_doc and organization_doc.organization_logo %}
        <img src="{{ organization_doc.organization_logo }}" style="max-height:48px; max-width:160px;" />
      {% else %}
        {{ organization or 'Anonymous Organization' }}
      {% endif %}
    </div>
    <div class="lh-address">
      {% if org_address %}
        {{ org_address.address_line1 }}<br>
        {% if org_address.address_line2 %}{{ org_address.address_line2 }}<br>{% endif %}
        {{ org_address.city }}{% if org_address.state %}, {{ org_address.state }}{% endif %}{% if org_address.pincode %} {{ org_address.pincode }}{% endif %}<br>
        {{ org_address.country }}<br>
        {% if org_address.phone %}<br>{{ org_address.phone }}{% endif %}
      {% endif %}
    </div>
  </div>

  <!-- Document Title -->
  <div class="doc-title">
    <h1>Deal Proposal</h1>
    <div class="doc-meta">
      <span><strong>Ref: </strong>{{ doc.name }}</span>
      {% if doc.expected_closure_date %}
      <span><strong>Valid Until: </strong>{{ frappe.format(doc.expected_closure_date, {'fieldtype': 'Date'}) }}</span>
      {% endif %}
      <span><strong>Date: </strong>{{ frappe.format(frappe.utils.today(), {'fieldtype': 'Date'}) }}</span>
    </div>
  </div>

  <!-- To Block -->
  <div class="to-block">
    <div class="to-label">Prepared For</div>
    <div class="to-name">{{ doc.organization or doc.organization_name or ([doc.salutation, doc.first_name, doc.last_name] | select | join(' ')) or '—' }}</div>
    <div class="to-meta">
      {% set contact_name = ([doc.salutation, doc.first_name, doc.last_name] | select | join(' ')) %}
      {% if contact_name and doc.organization %}<span>{{ contact_name }}</span><br>{% endif %}
      {% if doc.job_title %}<span>{{ doc.job_title }}</span><br>{% endif %}
      {% if doc.email %}<span>{{ doc.email }}</span>{% if doc.mobile_no %} &nbsp;·&nbsp; {% endif %}{% endif %}
      {% if doc.mobile_no %}<span>{{ doc.mobile_no }}</span>{% endif %}
      {% if doc.website %}<br><span>{{ doc.website }}</span>{% endif %}
    </div>
  </div>

  <!-- Deal Summary -->
  <div class="section">
    <div class="section-title">Deal Summary</div>
    <div class="fields-grid">
      {% if doc.deal_value %}
      <div class="field-row">
        <div class="field-label">Deal Value</div>
        <div class="field-value">{{ currency_symbol }} {{ '{:,.2f}'.format(doc.deal_value) }}</div>
      </div>
      {% endif %}
      {% if doc.currency %}
      <div class="field-row">
        <div class="field-label">Currency</div>
        <div class="field-value">{{ doc.currency }}</div>
      </div>
      {% endif %}
      {% if doc.next_step %}
      <div class="field-row" style="grid-column: 1 / -1">
        <div class="field-label">Next Step</div>
        <div class="field-value">{{ doc.next_step }}</div>
      </div>
      {% endif %}
    </div>
  </div>

  <!-- Products / Services -->
  {% if doc.products %}
  <div class="section">
    <div class="section-title">Products &amp; Services</div>
    <table class="products-table">
      <thead>
        <tr>
          <th style="width:30%">Item</th>
          <th>Description</th>
          <th class="ar" style="width:8%">Qty</th>
          <th class="ar" style="width:12%">Unit Price</th>
          <th class="ar" style="width:10%">Discount</th>
          <th class="ar" style="width:12%">Amount</th>
        </tr>
      </thead>
      <tbody>
        {% for product in doc.products %}
        <tr>
          <td><strong>{{ product.product_name or product.product_code or '—' }}</strong></td>
          <td style="color:#555">{{ product.description or '' }}</td>
          <td class="ar">{{ product.qty or '' }}</td>
          <td class="ar">{% if product.rate %}{{ currency_symbol }} {{ '{:,.2f}'.format(product.rate) }}{% endif %}</td>
          <td class="ar">
            {% if product.discount_percentage %}{{ product.discount_percentage }}%
            {% elif product.discount_amount %}{{ currency_symbol }} {{ '{:,.2f}'.format(product.discount_amount) }}
            {% endif %}
          </td>
          <td class="ar">{% if product.amount %}<strong>{{ currency_symbol }} {{ '{:,.2f}'.format(product.amount) }}</strong>{% endif %}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
    {% if doc.total or doc.net_total %}
    <div class="totals-block">
      {% if doc.total %}
      <div class="total-row">
        <span class="tl">Subtotal</span>
        <span class="tv">{{ currency_symbol }} {{ '{:,.2f}'.format(doc.total) }}</span>
      </div>
      {% endif %}
      {% if doc.net_total and doc.net_total != doc.total %}
      <div class="total-row grand">
        <span class="tl">Net Total</span>
        <span class="tv">{{ currency_symbol }} {{ '{:,.2f}'.format(doc.net_total) }}</span>
      </div>
      {% else %}
      <div class="total-row grand">
        <span class="tl">Total</span>
        <span class="tv">{{ currency_symbol }} {{ '{:,.2f}'.format(doc.total or doc.net_total) }}</span>
      </div>
      {% endif %}
    </div>
    {% endif %}
  </div>
  {% endif %}

  <!-- Footer -->
  <div class="pf-footer">
    <span class="ref">Ref: {{ doc.name }}</span>
    <span class="date">Generated {{ frappe.format(frappe.utils.today(), {'fieldtype': 'Date'}) }}</span>
  </div>

</div>
